export interface Task {
  title: string;
  done: boolean;
  hours: number;
}

export interface ReportInput {
  title: string;
  tasks: Task[];
}

export interface ReportOptions {
  separator?: string;
  bullet?: string;
  sections?: string[];
  theme?: string;
  locale?: string;
  outputFormat?: "text";
}

const DEFAULT_OPTIONS: Required<ReportOptions> = {
  separator: "=",
  bullet: "-",
  sections: ["header", "tasks", "footer"],
  theme: "default",
  locale: "en",
  outputFormat: "text",
};

const MESSAGES = {
  en: {
    done: "done",
    total: "total",
    doneLabel: "Done",
    openLabel: "Open",
    hoursLabel: "Hours",
  },
};

function formatHours(hours: number): string {
  return `${hours}h`;
}

function calculateStats(tasks: Task[]): { doneCount: number; totalHours: number } {
  let doneCount = 0;
  let totalHours = 0;
  for (const task of tasks) {
    if (task.done) doneCount += 1;
    totalHours += task.hours;
  }
  return { doneCount, totalHours };
}

interface Ctx {
  input: ReportInput;
  separator: string;
  bullet: string;
  messages: typeof MESSAGES.en;
}

function renderHeader(ctx: Ctx): string[] {
  const { title } = ctx.input;
  return [title, ctx.separator.repeat(title.length)];
}

function renderTasks(ctx: Ctx): string[] {
  return ctx.input.tasks.map((task) => {
    const marker = task.done ? "[x]" : "[ ]";
    return `${ctx.bullet} ${marker} ${task.title} (${formatHours(task.hours)})`;
  });
}

function renderSummary(ctx: Ctx): string[] {
  const { tasks } = ctx.input;
  const { doneCount, totalHours } = calculateStats(tasks);
  return [
    `${ctx.messages.doneLabel}: ${doneCount}`,
    `${ctx.messages.openLabel}: ${tasks.length - doneCount}`,
    `${ctx.messages.hoursLabel}: ${formatHours(totalHours)}`,
  ];
}

function renderFooter(ctx: Ctx): string[] {
  const { tasks } = ctx.input;
  const { doneCount, totalHours } = calculateStats(tasks);
  return [
    `${doneCount}/${tasks.length} ${ctx.messages.done}, ${formatHours(totalHours)} ${ctx.messages.total}`,
  ];
}

const RENDERERS: Record<string, (ctx: Ctx) => string[]> = {
  header: renderHeader,
  tasks: renderTasks,
  summary: renderSummary,
  footer: renderFooter,
};

export function formatReport(input: ReportInput, options?: ReportOptions): string {
  const opts = { ...DEFAULT_OPTIONS, ...options };

  const messages = MESSAGES[opts.locale as keyof typeof MESSAGES];
  if (!messages) {
    throw new Error(`no messages for locale: ${opts.locale}`);
  }

  const ctx: Ctx = {
    input,
    separator: opts.separator,
    bullet: opts.bullet,
    messages,
  };

  const lines: string[] = [];
  for (const section of opts.sections) {
    const renderer = RENDERERS[section];
    if (!renderer) {
      throw new Error(`no renderer for section: ${section}`);
    }
    lines.push(...renderer(ctx));
  }

  return lines.join("\n");
}

